import { auth } from "@clerk/nextjs/server";

const ROLE_LEVEL: Record<string, number> = {
  Member: 1,
  Officer: 2,
  Admin: 3,
};

function json(body: object, status: number): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

/**
 * Server-side role check for API route handlers.
 * Returns a 401/403 Response if the check fails, or null if the caller may proceed.
 *
 * Usage:
 *   const guard = await withRoleProtection(request, "Officer");
 *   if (guard) return guard;
 */
export async function withRoleProtection(
  _request: Request,
  requiredRole: string
): Promise<Response | null> {
  const { userId, sessionClaims } = await auth();

  if (!userId) return json({ error: "Unauthorized" }, 401);

  const role = (sessionClaims?.publicMetadata as { role?: string } | undefined)?.role;
  const userLevel = ROLE_LEVEL[role ?? ""] ?? 0;
  const requiredLevel = ROLE_LEVEL[requiredRole] ?? 0;

  if (userLevel < requiredLevel) return json({ error: "Forbidden" }, 403);

  return null;
}
