/**
 * Mission Control engine — extends Brief with intent, continue-working,
 * action cards, agent panel, and momentum. Renders ranked attention, not menus.
 */

import {
  buildBriefResponse,
  scoreActivityEvent,
  type BriefAction,
  type BriefCard,
  type BriefRequest,
  type BriefResponse,
} from './brief-engine';
import type { PlatformEvent } from './platform-events';
import { mergeEventStreams } from './platform-events';
import { isActiveAgent, toAgentRun, type AgentRun } from './agent-events';
import type { ActivityEvent } from './activity-events';

export interface MissionControlRequest extends BriefRequest {
  userId?: string;
  role?: 'executive' | 'builder' | string;
}

export interface ContinueWorkingItem {
  id: string;
  title: string;
  summary: string;
  href: string;
  module: string;
  lastActiveAt: string;
}

export interface ActionCard {
  id: string;
  label: string;
  href: string;
  intent: string;
  module?: string;
}

export interface MomentumStat {
  label: string;
  value: number;
  unit?: string;
}

export interface MissionControlResponse extends BriefResponse {
  /** Example intents for the command bar placeholder. */
  intentExamples: string[];
  /** Ranked attention — same as brief cards, explicit alias for Mission Control. */
  todaysFocus: BriefCard[];
  continueWorking: ContinueWorkingItem[];
  actionCards: ActionCard[];
  agentRuns: AgentRun[];
  activeAgents: AgentRun[];
  momentum: MomentumStat[];
}

/** Default EA executive action cards — override per deploy. */
export const DEFAULT_ACTION_CARDS: ActionCard[] = [
  { id: 'new-client', label: 'New Client', href: '/admin/clients/new', intent: 'start new client', module: 'clients' },
  { id: 'proposal', label: 'Create Proposal', href: '/admin/proposals/new', intent: 'create proposal', module: 'simplifi' },
  { id: 'blueprint', label: 'Generate Blueprint', href: '/admin/blueprints/new', intent: 'generate blueprint', module: 'simplifi' },
  { id: 'portal', label: 'Build Portal', href: '/admin/build/portal', intent: 'build portal', module: 'build' },
  { id: 'landing', label: 'Build Landing Page', href: '/admin/build/landing', intent: 'build landing page', module: 'build' },
  { id: 'training', label: 'Create Training', href: '/admin/training/new', intent: 'create training', module: 'training' },
  { id: 'content', label: 'Publish Content', href: '/amplifi', intent: 'publish content', module: 'amplifi' },
  { id: 'launch', label: 'Launch Project', href: '/launch', intent: 'launch project', module: 'pulse' },
];

export const DEFAULT_INTENT_EXAMPLES = [
  'Create proposal for Bob',
  'Build volunteer portal',
  'Continue yesterday\'s work',
  'Review opportunities',
  'Generate Blueprint',
  'Launch client project',
];

export function buildMissionControlResponse(
  events: PlatformEvent[],
  request: MissionControlRequest,
  options: {
    actionCards?: ActionCard[];
    quickActions?: BriefAction[];
    intentExamples?: string[];
    agentRuns?: AgentRun[];
  } = {},
): MissionControlResponse {
  const brief = buildBriefResponse(events, request, options.quickActions);
  const actionCards = filterActionCardsByRole(
    options.actionCards ?? DEFAULT_ACTION_CARDS,
    request.role,
  );
  const agentRuns = options.agentRuns ?? extractAgentRuns(events);
  const activeAgents = agentRuns.filter(isActiveAgent);
  const continueWorking = extractContinueWorking(events, request);
  const momentum = computeMomentum(events, request);
  const todaysFocus = brief.cards.map(enrichCardWithWhy);

  return {
    ...brief,
    intentExamples: options.intentExamples ?? DEFAULT_INTENT_EXAMPLES,
    todaysFocus,
    topPriority: todaysFocus[0] ?? brief.topPriority,
    recommendedActions: todaysFocus.filter((c) => c.actionLabel).slice(0, 3),
    continueWorking,
    actionCards,
    agentRuns,
    activeAgents,
    momentum,
  };
}

/** Build from separate pulse + activity streams (ea-payments adapter path). */
export function buildMissionControlFromStreams(
  activity: ActivityEvent[],
  pulse: PlatformEvent[],
  request: MissionControlRequest,
  options: Parameters<typeof buildMissionControlResponse>[2] = {},
): MissionControlResponse {
  return buildMissionControlResponse(mergeEventStreams(activity, pulse), request, options);
}

function extractContinueWorking(
  events: PlatformEvent[],
  request: MissionControlRequest,
): ContinueWorkingItem[] {
  return events
    .filter((e) => e.organizationId === request.organizationId)
    .filter(
      (e) =>
        e.category === 'continue' ||
        Boolean(e.metadata.continueUrl) ||
        e.eventType.toLowerCase().includes('paused') ||
        e.eventType.toLowerCase().includes('in_progress'),
    )
    .map((e) => ({
      id: e.id,
      title: readStr(e.metadata.continueTitle) || e.title,
      summary: e.summary,
      href: readStr(e.metadata.continueUrl) || e.actionUrl || '#',
      module: e.module,
      lastActiveAt: e.createdAt,
    }))
    .sort((a, b) => new Date(b.lastActiveAt).getTime() - new Date(a.lastActiveAt).getTime())
    .slice(0, 6);
}

function extractAgentRuns(events: PlatformEvent[]): AgentRun[] {
  return events
    .filter((e) => e.module === 'agent' || e.metadata.agentKind)
    .map((e) => toAgentRun(e))
    .slice(0, 10);
}

function computeMomentum(events: PlatformEvent[], request: MissionControlRequest): MomentumStat[] {
  const now = request.time ? new Date(request.time) : new Date();
  const today = events.filter(
    (e) =>
      e.organizationId === request.organizationId &&
      isSameDay(new Date(e.createdAt), now),
  );

  const advanced = today.filter(
    (e) =>
      e.eventType.includes('completed') ||
      e.eventType.includes('advanced') ||
      e.metadata.momentum === 'advanced',
  ).length;

  const proposals = today.filter((e) => e.eventType.includes('proposal')).length;
  const opportunities = today.filter((e) => e.eventType.includes('opportunity') || e.eventType.includes('capture')).length;
  const onboarded = today.filter((e) => e.eventType.includes('onboard')).length;

  const stats: MomentumStat[] = [];
  if (advanced > 0) stats.push({ label: 'Projects advanced', value: advanced });
  if (proposals > 0) stats.push({ label: 'Proposals completed', value: proposals });
  if (opportunities > 0) stats.push({ label: 'Opportunities discovered', value: opportunities });
  if (onboarded > 0) stats.push({ label: 'Clients onboarded', value: onboarded });

  return stats;
}

function enrichCardWithWhy(card: BriefCard): BriefCard {
  const why =
    readStr(card.metadata.whyRecommended) ||
    readStr(card.metadata.recommendationReason);
  if (!why) return card;
  return {
    ...card,
    summary: card.summary.includes(why) ? card.summary : `${card.summary} ${why}`.trim(),
  };
}

function filterActionCardsByRole(cards: ActionCard[], role?: string): ActionCard[] {
  if (role === 'builder') return cards;
  // Executive mode: hide builder-only paths
  const builderOnly = new Set(['portal', 'landing']);
  return cards.filter((c) => !builderOnly.has(c.id));
}

function isSameDay(a: Date, b: Date): boolean {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
}

function readStr(value: unknown): string {
  return typeof value === 'string' ? value : '';
}