import { clerkMiddleware, createRouteMatcher } from "@clerk/nextjs/server";
import type { NextFetchEvent, NextRequest } from "next/server";

export interface MiddlewareConfig {
  protectedPrefixes: string[];
  adminPrefixes: string[];
  publicRoutes: string[];
}

/**
 * Returns a ready-to-export Clerk middleware and its Next.js matcher config.
 *
 * Usage in middleware.ts:
 *   const { middleware, config } = createPortalMiddleware({ ... });
 *   export default middleware;
 *   export { config };
 */
export function createPortalMiddleware(cfg: MiddlewareConfig) {
  const isPublic = createRouteMatcher(cfg.publicRoutes.map((r) => `${r}(.*)?`));
  const isAdmin = createRouteMatcher(cfg.adminPrefixes.map((r) => `${r}(.*)`));

  const middleware = clerkMiddleware(async (auth, request: NextRequest) => {
    if (isPublic(request)) return;

    await auth.protect();

    if (isAdmin(request)) {
      const { sessionClaims } = await auth();
      const role = (sessionClaims?.publicMetadata as { role?: string } | undefined)?.role;
      if (role !== "Officer" && role !== "Admin") {
        return new Response(JSON.stringify({ error: "Forbidden" }), {
          status: 403,
          headers: { "Content-Type": "application/json" },
        });
      }
    }
  });

  const config = {
    matcher: ["/((?!_next/static|_next/image|favicon\\.ico).*)"],
  };

  return { middleware, config };
}
