"use client";

import { SignIn, SignUp } from "@clerk/nextjs";
import type { CSSProperties } from "react";

export interface ClerkShellProps {
  brandColor: string;
  logoSrc: string;
  portalName: string;
  tagline: string;
  mode: "sign-in" | "sign-up";
}

/**
 * Universal login/signup shell used across all EA portals.
 * Left panel: brand color, logo, tagline. Right panel: Clerk component.
 * Left panel collapses below 768px so only the Clerk form is visible on mobile.
 */
export function ClerkShell({ brandColor, logoSrc, portalName, tagline, mode }: ClerkShellProps) {
  return (
    <>
      <style>{`
        .cs-root {
          display: flex;
          min-height: 100vh;
          min-height: 100dvh;
        }
        .cs-left {
          flex: 0 0 50%;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: var(--space-12, 48px) var(--space-8, 32px);
          gap: var(--space-6, 24px);
        }
        .cs-logo {
          width: 80px;
          height: 80px;
          object-fit: contain;
        }
        .cs-portal-name {
          margin: 0;
          color: #ffffff;
          font-family: var(--font-display, 'Inter', sans-serif);
          font-size: 2rem;
          font-weight: 700;
          text-align: center;
        }
        .cs-tagline {
          margin: 0;
          color: rgba(255, 255, 255, 0.8);
          font-family: var(--font-body, 'Inter', sans-serif);
          font-size: 1rem;
          text-align: center;
          max-width: 320px;
          line-height: 1.5;
        }
        .cs-right {
          flex: 1;
          display: flex;
          align-items: center;
          justify-content: center;
          background-color: var(--color-bg, #ffffff);
          padding: var(--space-12, 48px) var(--space-6, 24px);
        }
        @media (max-width: 768px) {
          .cs-left { display: none; }
          .cs-right { flex: 1; width: 100%; }
        }
      `}</style>

      <div className="cs-root">
        <div className="cs-left" style={{ backgroundColor: brandColor } as CSSProperties}>
          <img src={logoSrc} alt={`${portalName} logo`} className="cs-logo" />
          <h1 className="cs-portal-name">{portalName}</h1>
          <p className="cs-tagline">{tagline}</p>
        </div>

        <div className="cs-right">
          {mode === "sign-in" ? <SignIn /> : <SignUp />}
        </div>
      </div>
    </>
  );
}
